+            sample_cached_query_plan("t2-v11")
+        });
+
+        assert_eq!(planner.plan_cache_len(), 2);
+
+        let rebuilt_plan_a = planner.cached_plan("SELECT * FROM t1", 12, || {
+            build_count.set(build_count.get() + 1);
+            sample_cached_query_plan("t1-v12")
+        });
